@import './styles/tokens.css';
@import './styles/typography.css';

import { Code, Heading, Text } from '@/components/nerio/components/typography';

<Heading as="h2" size="lg">Workspace settings</Heading>
<Text tone="secondary">Changes apply to every member.</Text>
<Code>nerio add typography</Code>

import { Settings } from '@nerio-ui/adapters/icons';
import { Button } from '@/components/nerio/components/button';

<Button icon={Settings} aria-label="Workspace settings" tooltip="Workspace settings" />

import { Settings } from '@nerio-ui/adapters/icons';
import { Button } from '@/components/nerio/components/button';

// Preferred replacement
<Button icon={Settings} aria-label="Workspace settings" />

import { Button } from '@/components/nerio/components/button';
import { ButtonGroup } from '@/components/nerio/components/button-group';

<ButtonGroup aria-label="Document actions" orientation="vertical"><Button variant="secondary">Cancel</Button><Button variant="secondary">Save</Button></ButtonGroup>

import { Check } from '@nerio-ui/adapters/icons';
import { Badge } from '@/components/nerio/components/badge';

<Badge tone="success" leadingIcon={Check}>Published</Badge>

import { Circle } from '@nerio-ui/adapters/icons';
import { Alert } from '@/components/nerio/components/alert';

<Alert tone="info" title="Invite sent" icon={Circle}>Collaborators will receive an email shortly.</Alert>

import { Progress } from '@/components/nerio/components/progress';

<Progress label="Uploading files" value={68} />

<Progress aria-label="Synchronizing workspace" value={null} valueText="Synchronizing" />

import { Table, TableBody, TableCaption, TableCell, TableContainer, TableHead, TableHeader, TableRow } from '@/components/nerio/components/table';

<h2 id="projects-title">Projects</h2>
<TableContainer focusable aria-labelledby="projects-title"><Table><TableCaption>Current projects</TableCaption><TableHeader><TableRow><TableHead>Name</TableHead></TableRow></TableHeader><TableBody><TableRow><TableCell>Roadmap</TableCell></TableRow></TableBody></Table></TableContainer>

import { RadioGroup, RadioGroupItem } from '@/components/nerio/components/radio-group';

<RadioGroup label="Visibility" name="visibility" defaultValue="team">
  <RadioGroupItem value="private">Private</RadioGroupItem>
  <RadioGroupItem value="team">Team</RadioGroupItem>
</RadioGroup>

// options remains supported for concise data-driven groups.

import { Field } from '@/components/nerio/components/field';
import { Input } from '@/components/nerio/components/input';

<Field label="Project name" description="Use a short recognizable name."><Input placeholder="Launch materials" required autoComplete="organization" /></Field>

import { Input } from '@/components/nerio/components/input';
import { InputGroup, InputGroupAddon } from '@/components/nerio/components/input-group';

<InputGroup><InputGroupAddon placement="start" aria-hidden="true">https://</InputGroupAddon><Input aria-label="Website" /><InputGroupAddon placement="end" aria-hidden="true">.com</InputGroupAddon></InputGroup>

import { Field } from '@/components/nerio/components/field';
import { Textarea } from '@/components/nerio/components/textarea';

<Field label="Notes" description="Add useful context for collaborators."><Textarea placeholder="Add context" /></Field>

import { Input, Label, LabelContent, LabelRequired, LabelRow } from '@/components/nerio/components/label';
import { LabelHint } from '@/components/nerio/components/label-hint';

<LabelRow><LabelContent><Label htmlFor="name">Project name</Label><LabelRequired /><LabelHint label="Used in navigation." /></LabelContent></LabelRow><Input id="name" required />

import { Field } from '@/components/nerio/components/field';
import { Input } from '@/components/nerio/components/input';

<Field label="Project name" description="Shown in workspace navigation." message="Use at least 3 characters." invalid><Input /></Field>

import { Kbd } from '@/components/nerio/components/kbd';
import { Command, CommandEmpty, CommandInput, CommandItem, CommandList } from '@/components/nerio/components/command';

const items = [
  { value: 'settings', label: 'Workspace settings', keywords: ['preferences'] },
  { value: 'archive', label: 'Archive project', disabled: true },
];

<Command items={items}>
  <CommandInput aria-label="Workspace commands" placeholder="Search commands" />
  <CommandEmpty>No matching commands.</CommandEmpty>
  <CommandList>
    {(item) => (
      <CommandItem key={item.value} value={item.value} disabled={item.disabled} shortcut={<Kbd aria-hidden>⌘,</Kbd>} onSelect={(value, event) => runCommand(value, event)}>
        {item.label}
      </CommandItem>
    )}
  </CommandList>
</Command>

// Selecting by the keyword "preferences" writes "Workspace settings" to the query; onSelect receives "settings".

import { Button } from '@/components/nerio/components/button';
import { ToastProvider, ToastViewport, useToastManager } from '@/components/nerio/components/toast';

function SaveButton() {
  const toasts = useToastManager();
  return <Button onClick={() => toasts.add({ id: 'save-result', title: 'Saved', timeout: 5000, priority: 'low', data: { tone: 'success', action: { label: 'Undo', onClick: undo } } })}>Save</Button>;
}

<ToastProvider limit={3}><SaveButton /><ToastViewport label="Notifications" dismissText="Dismiss" dismissLabel="Dismiss notification" /></ToastProvider>
